const payload = JSON.parse($input.item.json.message);
const after = payload.after || {};
const data = after.data || {};

const isVogelbad = after.camera === 'vogelbad';
const objects = data.objects || [];
const isBird = objects.includes('bird');
const isEnd = payload.type === 'end';
const detectionId = (data.detections || [])[0];

if (!isBird || !isVogelbad || !isEnd || !detectionId) {
  return [];
}

return [{
  json: {
    event_id: detectionId,
    review_id: after.id,
    camera: after.camera,
    start_time: after.start_time,
    end_time: after.end_time
  }
}];

const raw = $input.item.json.response;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { umgangssprachlich: 'Parse-Fehler', lateinisch: '', konfidenz: 0, ist_vogel: false, anmerkung: String(raw).slice(0,200) };
}

const eventId = $node['Filter: neues Vogel-Event mit Snapshot'].json.event_id;

return [{
  json: {
    event_id: eventId,
    umgangssprachlich: parsed.umgangssprachlich || 'unbekannt',
    lateinisch: parsed.lateinisch || '',
    konfidenz: parsed.konfidenz ?? 0,
    ist_vogel: parsed.ist_vogel ?? true,
    anmerkung: parsed.anmerkung || '',
    zeitstempel: new Date().toISOString(),
    bild_url: `http://<frigate-host>:5000/api/events/${eventId}/snapshot.jpg`
  }
}];

const fs = require('fs');
const path = '/home/node/.n8n/vogelbad_historie.json';

let historie = [];
try {
  historie = JSON.parse(fs.readFileSync(path, 'utf8'));
} catch (e) {
  historie = [];
}

historie.unshift({
  event_id: $json.event_id,
  umgangssprachlich: $json.umgangssprachlich,
  lateinisch: $json.lateinisch,
  konfidenz: $json.konfidenz,
  anmerkung: $json.anmerkung,
  zeitstempel: $json.zeitstempel,
  bild_url: $json.bild_url
});

historie = historie.slice(0, 200);
fs.writeFileSync(path, JSON.stringify(historie, null, 2));

return [{ json: $json }];
